// PizzaModal.jsx - Componente Modal
import React from 'react';
import styled from 'styled-components';

const PizzaModal = ({ pizza, onClose }) => {
  const handleOverlayClick = (e: React.MouseEvent) => {
    if (e.target === e.currentTarget) {
      onClose();
    }
  };

  return (
    <Overlay onClick={handleOverlayClick}>
      <ModalContent onClick={(e) => e.stopPropagation()}>
        <CloseButton onClick={onClose}>&times;</CloseButton>
        <ModalImage src={pizza.image} alt={pizza.name} />
        <ModalInfo>
          <ModalName>{pizza.name}</ModalName>
          <ModalDescription>{pizza.description}</ModalDescription>
          <ModalPrice>R$ {pizza.price.toFixed(2)}</ModalPrice>
        </ModalInfo>
      </ModalContent>
    </Overlay>
  );
};

export default PizzaModal;

// Estilos com styled-components
const Overlay = styled.div`
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.7);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 1000;
`;

const ModalContent = styled.div`
  background: #fff;
  border-radius: 8px;
  max-width: 500px;
  width: 90%;
  max-height: 80vh;
  overflow-y: auto;
  position: relative;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.3);
`;

const CloseButton = styled.button`
  position: absolute;
  top: 10px;
  right: 10px;
  background: none;
  border: none;
  font-size: 2rem;
  cursor: pointer;
  color: #333;
  z-index: 1;

  &:hover {
    color: #e74c3c;
  }
`;

const ModalImage = styled.img`
  width: 100%;
  height: 250px;
  object-fit: cover;
  border-radius: 8px 8px 0 0;
`;

const ModalInfo = styled.div`
  padding: 20px;
`;

const ModalName = styled.h2`
  margin: 0 0 15px 0;
  font-size: 1.5rem;
  color: #333;
`;

const ModalDescription = styled.p`
  margin: 0 0 15px 0;
  color: #666;
  line-height: 1.5;
`;

const ModalPrice = styled.p`
  margin: 0;
  font-size: 1.3rem;
  font-weight: bold;
  color: #e74c3c;
`;
